function Update-Certificate { 
    param(
        [switch]$Unattended
    )

    $decision = 0

    if (-not $Unattended) {
        $title = 'Fixing the Intune Enrollment'
        $question = 'Are you 100% sure you want to proceed? Because I will break everything...or not!!!!!'
        $choices = '&Yes', '&No'
        $decision = $Host.UI.PromptForChoice($title, $question, $choices, 1)
    }

    if ($decision -eq 0) {
        $progressPreference = 'silentlyContinue'
        Write-Host "Trying to enroll your device into Intune or something else..." -foregroundcolor yellow
        Update-MDMUrl
        Invoke-WebRequest -Uri 'https://download.sysinternals.com/files/PSTools.zip' -OutFile 'pstools.zip'
        Expand-Archive -Path 'pstools.zip' -DestinationPath "$env:TEMP\pstools" -force
        #Move-Item -Path "$env:TEMP\pstools\psexec.exe" -force
        reg.exe ADD HKCU\Software\Sysinternals /v EulaAccepted /t REG_DWORD /d 1 /f | out-null
        $enroll = Start-Process -windowstyle hidden -FilePath "$env:TEMP\pstools\psexec.exe" -ArgumentList '-s cmd /c "powershell.exe -ExecutionPolicy Bypass -encodedcommand "' 
        $enroll
        Write-Host "`n"

        Write-Host "Please give the OMA DM client some time (about 30 seconds)to sync and get your device enrolled into Intune" -foregroundcolor yellow
        Write-Host "`n"
        Start-Sleep -seconds 30
        Write-Host "Checking the Intune Certificate Again!." -foregroundcolor yellow
        Test-IntuneCertificate
        Test-DMWapService
        Get-ScheduledTask | ? { $_.TaskName -eq 'Schedule #1 created by enrollment client' } | Start-ScheduledTask
        Start-Sleep -seconds 10

        try {
            Start-IntuneSync
        }

        catch {
            Write-Warning "Intune Sync could not be started. This isn't the end of the world"
        }

        Test-DMPCertificate

        Start-Sleep -seconds 5

        Get-Schedule1
        if (-not $Unattended) {
            Read-Host -prompt "Press any key to continue..."
        }
        exit    
    }
    else {
        Write-Host "`n"
        Write-Host 'You dont like me fixing it...? Fine...exiting now' -fo1:48 AM 3/22/2023regroundcolor red
        exit 1
    }
}